   318→func bootstrapExistingClusterNoWAL(cfg config.ServerConfig, prt http.RoundTripper) (*bootstrappedCluster, error) {
   319→	if err := cfg.VerifyJoinExisting(); err != nil {
   320→		return nil, err
   321→	}
   322→	cl, err := membership.NewClusterFromURLsMap(cfg.Logger, cfg.InitialClusterToken, cfg.InitialPeerURLsMap, membership.WithMaxLearners(cfg.MaxLearners))
   323→	if err != nil {
   324→		return nil, err
   325→	}
   326→	existingCluster, gerr := GetClusterFromRemotePeers(cfg.Logger, getRemotePeerURLs(cl, cfg.Name), prt)
   327→	if gerr != nil {
   328→		return nil, fmt.Errorf("cannot fetch cluster info from peer urls: %w", gerr)
   329→	}
   330→	if err := membership.ValidateClusterAndAssignIDs(cfg.Logger, cl, existingCluster); err != nil {
   331→		return nil, fmt.Errorf("error validating peerURLs %s: %w", existingCluster, err)
   332→	}
   333→	if !isCompatibleWithCluster(cfg.Logger, cl, cl.MemberByName(cfg.Name).ID, prt, cfg.ReqTimeout()) {
   334→		return nil, fmt.Errorf("incompatible with current running cluster")
   335→	}
   336→	scaleUpLearners := false
   337→	if err := membership.ValidateMaxLearnerConfig(cfg.MaxLearners, existingCluster.Members(), scaleUpLearners); err != nil {
   338→		return nil, err
   339→	}
   340→	remotes := existingCluster.Members()
   341→	cl.SetID(types.ID(0), existingCluster.ID())
   342→	member := cl.MemberByName(cfg.Name)
   343→	return &bootstrappedCluster{
   344→		remotes: remotes,
   345→		cl:      cl,
   346→		nodeID:  member.ID,
   347→	}, nil
   348→}
   349→
   350→func bootstrapNewClusterNoWAL(cfg config.ServerConfig, prt http.RoundTripper) (*bootstrappedCluster, error) {
   351→	if err := cfg.VerifyBootstrap(); err != nil {
   352→		return nil, err
   353→	}
   354→	cl, err := membership.NewClusterFromURLsMap(cfg.Logger, cfg.InitialClusterToken, cfg.InitialPeerURLsMap, membership.WithMaxLearners(cfg.MaxLearners))
   355→	if err != nil {
   356→		return nil, err
   357→	}
   358→	m := cl.MemberByName(cfg.Name)
   359→	if isMemberBootstrapped(cfg.Logger, cl, cfg.Name, prt, cfg.BootstrapTimeoutEffective()) {
   360→		return nil, fmt.Errorf("member %s has already been bootstrapped", m.ID)
   361→	}
   362→	if cfg.ShouldDiscover() {
   363→		cfg.Logger.Info("Bootstrapping cluster using v3 discovery.")
   364→		str, err := v3discovery.JoinCluster(cfg.Logger, &cfg.DiscoveryCfg, m.ID, cfg.InitialPeerURLsMap.String())
   365→		if err != nil {
   366→			return nil, &servererrors.DiscoveryError{Op: "join", Err: err}
   367→		}
   368→		var urlsmap types.URLsMap
   369→		urlsmap, err = types.NewURLsMap(str)
   370→		if err != nil {
   371→			return nil, err
   372→		}
   373→		if config.CheckDuplicateURL(urlsmap) {
   374→			return nil, fmt.Errorf("discovery cluster %s has duplicate url", urlsmap)
   375→		}
   376→		if cl, err = membership.NewClusterFromURLsMap(cfg.Logger, cfg.InitialClusterToken, urlsmap, membership.WithMaxLearners(cfg.MaxLearners)); err != nil {
   377→			return nil, err
   378→		}
   379→	}
   380→	return &bootstrappedCluster{
   381→		remotes: nil,
   382→		cl:      cl,
   383→		nodeID:  m.ID,
   384→	}, nil
   385→}
