   553→func (b *bootstrappedRaft) newRaftNode(ss *snap.Snapshotter, wal *wal.WAL, cl *membership.RaftCluster) *raftNode {
   554→	var n raft.Node
   555→	if len(b.peers) == 0 {
   556→		n = raft.RestartNode(b.config)
   557→	} else {
   558→		n = raft.StartNode(b.config, b.peers)
   559→	}
   560→	raftStatusMu.Lock()
   561→	raftStatus = n.Status
   562→	raftStatusMu.Unlock()
   563→	return newRaftNode(
   564→		raftNodeConfig{
   565→			lg:          b.lg,
   566→			isIDRemoved: func(id uint64) bool { return cl.IsIDRemoved(types.ID(id)) },
   567→			Node:        n,
   568→			heartbeat:   b.heartbeat,
   569→			raftStorage: b.storage,
   570→			storage:     serverstorage.NewStorage(b.lg, wal, ss),
   571→		},
   572→	)
   573→}
   574→
   575→func bootstrapWALFromSnapshot(cfg config.ServerConfig, snapshot *raftpb.Snapshot, ci cindex.ConsistentIndexer) *bootstrappedWAL {
   576→	wal, st, ents, snap, meta := openWALFromSnapshot(cfg, snapshot)
   577→	bwal := &bootstrappedWAL{
   578→		lg:       cfg.Logger,
   579→		w:        wal,
   580→		st:       st,
   581→		ents:     ents,
   582→		snapshot: snap,
   583→		meta:     meta,
   584→		haveWAL:  true,
   585→	}
   586→
   587→	if cfg.ForceNewCluster {
   588→		consistentIndex := ci.ConsistentIndex()
   589→		oldCommitIndex := bwal.st.Commit
   590→		// If only `HardState.Commit` increases, HardState won't be persisted
   591→		// to disk, even though the committed entries might have already been
   592→		// applied. This can result in consistent_index > CommitIndex.
   593→		//
   594→		// When restarting etcd with `--force-new-cluster`, all uncommitted
   595→		// entries are dropped. To avoid losing entries that were actually
   596→		// committed, we reset Commit to max(HardState.Commit, consistent_index).
   597→		//
   598→		// See: https://github.com/etcd-io/raft/pull/300 for more details.
   599→		bwal.st.Commit = max(oldCommitIndex, consistentIndex)
   600→
   601→		// discard the previously uncommitted entries
   602→		bwal.ents = bwal.CommitedEntries()
   603→		entries := bwal.NewConfigChangeEntries()
   604→		// force commit config change entries
   605→		bwal.AppendAndCommitEntries(entries)
   606→		cfg.Logger.Info(
   607→			"forcing restart member",
   608→			zap.String("cluster-id", meta.clusterID.String()),
   609→			zap.String("local-member-id", meta.nodeID.String()),
   610→			zap.Uint64("wal-commit-index", oldCommitIndex),
   611→			zap.Uint64("commit-index", bwal.st.Commit),
   612→		)
   613→	} else {
   614→		cfg.Logger.Info(
   615→			"restarting local member",
   616→			zap.String("cluster-id", meta.clusterID.String()),
   617→			zap.String("local-member-id", meta.nodeID.String()),
   618→			zap.Uint64("commit-index", bwal.st.Commit),
   619→		)
   620→	}
   621→	return bwal
   622→}
   623→
   624→// openWALFromSnapshot reads the WAL at the given snap and returns the wal, its latest HardState and cluster ID, and all entries that appear
   625→// after the position of the given snap in the WAL.
   626→// The snap must have been previously saved to the WAL, or this call will panic.
   627→func openWALFromSnapshot(cfg config.ServerConfig, snapshot *raftpb.Snapshot) (*wal.WAL, *raftpb.HardState, []raftpb.Entry, *raftpb.Snapshot, *snapshotMetadata) {
   628→	var walsnap walpb.Snapshot
   629→	if snapshot != nil {
   630→		walsnap.Index, walsnap.Term = snapshot.Metadata.Index, snapshot.Metadata.Term
   631→	}
   632→	repaired := false
   633→	for {
   634→		w, err := wal.Open(cfg.Logger, cfg.WALDir(), walsnap)
   635→		if err != nil {
   636→			cfg.Logger.Fatal("failed to open WAL", zap.Error(err))
   637→		}
   638→		if cfg.UnsafeNoFsync {
   639→			w.SetUnsafeNoFsync()
   640→		}
   641→		wmetadata, st, ents, err := w.ReadAll()
   642→		if err != nil {
   643→			w.Close()
   644→			// we can only repair ErrUnexpectedEOF and we never repair twice.
   645→			if repaired || !errors.Is(err, io.ErrUnexpectedEOF) {
   646→				cfg.Logger.Fatal("failed to read WAL, cannot be repaired", zap.Error(err))
   647→			}
   648→			if !wal.Repair(cfg.Logger, cfg.WALDir()) {
   649→				cfg.Logger.Fatal("failed to repair WAL", zap.Error(err))
   650→			} else {
   651→				cfg.Logger.Info("repaired WAL", zap.Error(err))
   652→				repaired = true
   653→			}
   654→			continue
   655→		}
   656→		var metadata etcdserverpb.Metadata
   657→		pbutil.MustUnmarshal(&metadata, wmetadata)
   658→		id := types.ID(metadata.NodeID)
   659→		cid := types.ID(metadata.ClusterID)
   660→		meta := &snapshotMetadata{clusterID: cid, nodeID: id}
   661→		return w, &st, ents, snapshot, meta
   662→	}
   663→}
   664→
   665→type snapshotMetadata struct {
   666→	nodeID, clusterID types.ID
   667→}
   668→
   669→func bootstrapNewWAL(cfg config.ServerConfig, cl *bootstrappedCluster) *bootstrappedWAL {
   670→	metadata := pbutil.MustMarshal(
   671→		&etcdserverpb.Metadata{
   672→			NodeID:    uint64(cl.nodeID),
   673→			ClusterID: uint64(cl.cl.ID()),
   674→		},
   675→	)
   676→	w, err := wal.Create(cfg.Logger, cfg.WALDir(), metadata)
   677→	if err != nil {
   678→		cfg.Logger.Panic("failed to create WAL", zap.Error(err))
   679→	}
   680→	if cfg.UnsafeNoFsync {
   681→		w.SetUnsafeNoFsync()
   682→	}
   683→	return &bootstrappedWAL{
   684→		lg: cfg.Logger,
   685→		w:  w,
   686→	}
   687→}
   688→
   689→type bootstrappedWAL struct {
   690→	lg *zap.Logger
   691→
   692→	haveWAL  bool
   693→	w        *wal.WAL
   694→	st       *raftpb.HardState
   695→	ents     []raftpb.Entry
   696→	snapshot *raftpb.Snapshot
   697→	meta     *snapshotMetadata
   698→}
   699→
   700→func (wal *bootstrappedWAL) MemoryStorage() *raft.MemoryStorage {
   701→	s := raft.NewMemoryStorage()
   702→	if wal.snapshot != nil {
   703→		s.ApplySnapshot(*wal.snapshot)
   704→	}
   705→	if wal.st != nil {
   706→		s.SetHardState(*wal.st)
   707→	}
   708→	if len(wal.ents) != 0 {
   709→		s.Append(wal.ents)
   710→	}
   711→	return s
   712→}
   713→
   714→func (wal *bootstrappedWAL) CommitedEntries() []raftpb.Entry {
   715→	for i, ent := range wal.ents {
   716→		if ent.Index > wal.st.Commit {
   717→			wal.lg.Info(
   718→				"discarding uncommitted WAL entries",
   719→				zap.Uint64("entry-index", ent.Index),
   720→				zap.Uint64("commit-index-from-wal", wal.st.Commit),
   721→				zap.Int("number-of-discarded-entries", len(wal.ents)-i),
   722→			)
   723→			return wal.ents[:i]
   724→		}
   725→	}
   726→	return wal.ents
   727→}
   728→
   729→func (wal *bootstrappedWAL) NewConfigChangeEntries() []raftpb.Entry {
   730→	return serverstorage.CreateConfigChangeEnts(
   731→		wal.lg,
   732→		serverstorage.GetEffectiveNodeIDsFromWALEntries(wal.lg, wal.snapshot, wal.ents),
   733→		uint64(wal.meta.nodeID),
   734→		wal.st.Term,
   735→		wal.st.Commit,
   736→	)
   737→}
   738→
   739→func (wal *bootstrappedWAL) AppendAndCommitEntries(ents []raftpb.Entry) {
   740→	wal.ents = append(wal.ents, ents...)
   741→	err := wal.w.Save(raftpb.HardState{}, ents)
   742→	if err != nil {
   743→		wal.lg.Fatal("failed to save hard state and entries", zap.Error(err))
   744→	}
   745→	if len(wal.ents) != 0 {
   746→		wal.st.Commit = wal.ents[len(wal.ents)-1].Index
   747→	}
   748→}
